    "debugging_capability": "Strong for happy-path debugging. Structured logging with request IDs and OpenTelemetry tracing make normal request flows easy to follow. However, the two critical failure modes — silent duplicates and DLQ accumulation — are invisible to current instrumentation. An on-call engineer would not know duplicates are occurring or that the DLQ is growing."
  },

  "resilience_assessment": {
    "failure_modes": [
      { "scenario": "Data warehouse write timeout followed by retry", "handling": "unhandled", "recommendation": "Implement idempotent writes using a unique event ID (e.g., SHA of event payload + timestamp) as a deduplication key in the warehouse. Use INSERT ... ON CONFLICT DO NOTHING or equivalent." },
      { "scenario": "ACK lost after successful warehouse write", "handling": "unhandled", "recommendation": "Same idempotency fix. The event ID deduplication key makes re-ingestion safe regardless of cause." },
      { "scenario": "Dead-letter queue fills up indefinitely", "handling": "unhandled", "recommendation": "Deploy a DLQ consumer that (1) alerts when messages arrive, (2) retries with backoff to the warehouse, (3) ages out to cold storage after N attempts. Add a metric for DLQ depth and alert when depth > 0 for more than 5 minutes." },
      { "scenario": "Sustained 10k events/sec load", "handling": "handled", "recommendation": "Load tested and validated. No action needed." },
      { "scenario": "Data warehouse goes down entirely", "handling": "partial", "recommendation": "Circuit breaker and DLQ catch the failure, but without a DLQ consumer those events are never recovered. Fix the DLQ consumer to close this loop." }
    ],
    "retry_config": "Exponential backoff with 3 retries — appropriate, but dangerous without idempotent writes. Each retry is a potential duplicate.",
    "timeout_config": "Not explicitly detailed, but circuit breaker implies timeouts are configured. Acceptable.",
    "circuit_breakers": "Present on data warehouse writes. Well-designed. However, when the circuit closes and retries resume, previously-failed events that actually succeeded silently produce duplicates.",
    "graceful_degradation": "Partial. The service degrades to DLQ buffering during warehouse outages, which is the right pattern, but the DLQ has no consumer so degradation becomes silent data loss."
  },

