    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": ["DLQ consumer/processor service"],
      "new_queues_topics": [],
      "config_changes": ["Add deduplication key column/constraint to warehouse target table"],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": true,
      "reversible": true,
      "data_preserving": true,
      "large_table_impact": true,
      "details": "Adding a unique constraint or deduplication key index to a high-volume clickstream table requires careful migration. At 10k events/sec, the table grows fast — adding a unique index on a large existing table may require online DDL or a backfill strategy to avoid locking."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "integration_gap",
      "issue": "Non-idempotent warehouse writes with at-least-once delivery guarantees",
      "reason": "The retry strategy (circuit breaker + exponential backoff) and the at-least-once delivery model both assume writes are safe to repeat. They are not. Every retry is a silent duplicate. For an analytics service, this means inflated metrics, wrong business decisions, and eroded trust in the data platform. This must be fixed before shipping — it is not a nice-to-have.",
      "routed_to": "MJ"
    },
    {
      "type": "integration_gap",
      "issue": "Dead-letter queue has no consumer or alerting",
      "reason": "The DLQ gives the appearance of resilience but is actually a data black hole. Without a consumer, failed events are never recovered and never alerted on. In production, this means silent data loss during every warehouse disruption — exactly the scenario the DLQ was built to handle.",
      "routed_to": "MJ"
    }
  ],

  "confidence": {
    "level": 60,
    "high_confidence_areas": [
      "Observability stack is well-designed for happy-path operations",
      "Deployment and rollback strategy is production-ready",
      "Load testing validates throughput claims",
      "Circuit breaker pattern is correctly applied"
    ],
